@Composable
fun PrimaryButton(
    modifier: Modifier = Modifier,
    text: String
) {
    var isHovered by remember { mutableStateOf(false) }
    var isPressed by remember { mutableStateOf(false) }

    BoxWithConstraints {
        Box(
            modifier = modifier
                .pointerInput(Unit) {
                awaitPointerEventScope {
                    while (true) {
                        val event = awaitPointerEvent()
                        when (event.type) {
                            PointerEventType.Enter -> isHovered = true
                        PointerEventType.Exit -> isHovered = false
                        PointerEventType.Press -> isPressed = true
                        PointerEventType.Release -> isPressed = false
                        }
                    }
                }
            }
                .clip(RoundedCornerShape(topStart = 8.dp, topEnd = 4.dp, bottomEnd = 2.dp, bottomStart = 0.dp))
                .background(Color(0xFF6200EE))
                .drawWithContent { drawContent(); drawLine(Color(0xFF000000), Offset(0f, 2.dp.toPx() / 2), Offset(size.width, 2.dp.toPx() / 2), 2.dp.toPx()); drawLine(Color(0xFF000000), Offset(0f, size.height - 0.dp.toPx() / 2), Offset(size.width, size.height - 0.dp.toPx() / 2), 0.dp.toPx()); drawLine(Color(0xFF00FF00), Offset(3.dp.toPx() / 2, 0f), Offset(3.dp.toPx() / 2, size.height), 3.dp.toPx()); drawLine(Color(0xFFFF0000), Offset(size.width - 1.dp.toPx() / 2, 0f), Offset(size.width - 1.dp.toPx() / 2, size.height), 1.dp.toPx()) }
                .padding(top = 10.dp, end = 16.dp, bottom = 10.dp, start = 16.dp)
                .then(if (isHovered) Modifier.alpha(0.9f) else Modifier)
                .then(if (isPressed) Modifier.alpha(0.8f) else Modifier)
                .then(if (isPressed) Modifier.scale(0.98f) else Modifier)
                .then(if (maxWidth >= 768.dp) Modifier.border(1.dp, Color(0xFF00FF00)) else Modifier)
        ) {
            Text(
                text = text,
                fontWeight = FontWeight.SemiBold,
                color = Color(0xFFFFFFFF)
            )
        }
    }
}

