@Composable
fun InputField(
    modifier: Modifier = Modifier,
    text: String
) {
    var isFocused by remember { mutableStateOf(false) }

    Box(
        modifier = modifier
            .onFocusChanged { isFocused = it.isFocused }
            .focusable()
            .clip(RoundedCornerShape(topStart = 4.dp, topEnd = 4.dp, bottomEnd = 4.dp, bottomStart = 4.dp))
            .then(if (isFocused) Modifier.border(1.dp, Color(0xFF6200EE)) else Modifier.border(1.dp, Color(0xFFCCCCCC)))
            .padding(top = 8.dp, end = 12.dp, bottom = 8.dp, start = 12.dp)
    ) {
        Text(
            text = text,
            fontSize = 14.0.sp,
            color = Color(0xFF333333)
        )
    }
}

